1	const PROCESSING_FEE = 5;
2	
3	const BASE_PREMIUMS: Record<string, number> = {
4	  sword: 100,
5	  amulet: 60,
6	  staff: 80,
7	  potion: 40,
8	  rune: 25,
9	  moonstone: 25,
10	};
11	
12	const basePremiumForType = (type: string): number => {
13	  if (!(type in BASE_PREMIUMS)) throw new Error(`Unknown item type: ${type}`);
14	  return BASE_PREMIUMS[type];
15	};
16	
17	const CURSED_SURCHARGE_RATE = 0.5;
18	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
19	const HIGH_ENCHANTMENT_THRESHOLD = 5;
20	const LOYALTY_DISCOUNT_RATE = 0.2;
21	const LOYALTY_THRESHOLD_YEARS = 2;
22	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
23	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
24	
25	const DEDUCTIBLE = 100;
26	
27	const COMPONENT_TYPES = ["rune", "moonstone"];
28	const BLOCK_SIZE = 3;
29	const BLOCK_PREMIUM = 60;
30	
31	const componentPremium = (type: string, count: number): number =>
32	  count === BLOCK_SIZE ? BLOCK_PREMIUM : count * basePremiumForType(type);
33	
34	const itemSurcharge = (item: any): number => {
35	  const base = basePremiumForType(item.type);
36	  return (item.cursed ? base * CURSED_SURCHARGE_RATE : 0)
37	    + (item.enchantment >= HIGH_ENCHANTMENT_THRESHOLD ? base * HIGH_ENCHANTMENT_SURCHARGE_RATE : 0);
38	};
39	
40	const countByType = (items: any[]): Record<string, number> =>
41	  items.reduce((counts: Record<string, number>, item: any) => {
42	    counts[item.type] = (counts[item.type] ?? 0) + 1;
43	    return counts;
44	  }, {});
45	
46	const isComponent = (item: any): boolean => COMPONENT_TYPES.includes(item.type);
47	
48	const calculateQuotePremium = (items: any[], customer: any, stepIndex: number): number => {
49	  const regularItems = items.filter((item: any) => !isComponent(item));
50	  const components = items.filter(isComponent);
51	
52	  const regularBasePremium = regularItems.reduce(
53	    (sum, item) => sum + basePremiumForType(item.type), 0);
54	  const componentBasePremium = Object.entries(countByType(components)).reduce(
55	    (sum, [type, count]) => sum + componentPremium(type, count), 0);
56	  const policyBasePremium = regularBasePremium + componentBasePremium;
57	
58	  const totalSurcharges = regularItems.reduce(
59	    (sum, item) => sum + itemSurcharge(item), 0);
60	
61	  const loyaltyDiscount = customer.yearsWithMHPCO >= LOYALTY_THRESHOLD_YEARS
62	    ? policyBasePremium * LOYALTY_DISCOUNT_RATE
63	    : 0;
64	  const followUpDiscount = stepIndex > 0 ? policyBasePremium * FOLLOW_UP_DISCOUNT_RATE : 0;
65	  const firstInsuranceSurcharge = policyBasePremium * FIRST_INSURANCE_SURCHARGE_RATE;
66	
67	  const premium = policyBasePremium + totalSurcharges - loyaltyDiscount
68	    + firstInsuranceSurcharge - followUpDiscount;
69	  return Math.ceil(premium + PROCESSING_FEE);
70	};
71	
72	const calculateClaimPayout = (damages: any[]): number => {
73	  let payout = 0;
74	  for (const damage of damages) {
75	    payout += Math.max(0, damage.amount - DEDUCTIBLE);
76	  }
77	  return payout;
78	};
79	
80	export const processScenario = (scenario: any): any => ({
81	  results: scenario.steps.map((step: any, index: number) => {
82	    if (step.op === "claim") {
83	      return { payout: calculateClaimPayout(step.damages) };
84	    }
85	    return { premium: calculateQuotePremium(step.items, scenario.customer, index) };
86	  }),
87	});
